<template>
	<view class="page-container">
		<view class="form-box">
			<u-form :model="form" ref="uForm" label-width="140">
				<u-form-item label="姓名" prop="real_name" required>
					<u-input v-model.trim="form.real_name" />
				</u-form-item>
				<u-form-item label="联系电话" prop="mobile" required>
					<u-input v-model="form.mobile" />
				</u-form-item>
				<u-form-item label="所在地区" prop="address_id">
					<u-field v-model="areaNames" :clearable="false" readonly @click="handelAddressClick"
						placeholder="请选择所在地区" placeholder-style="color:#C0C4CC;" :label-width="0"
						:border-bottom="false">
						<u-button size="mini" slot="right" type="error" @click="$u.throttle(handelAddressClick,500)">
							<u-icon name="map" size="30rpx"></u-icon>
						</u-button>
					</u-field>
				</u-form-item>
				<u-form-item label="详细地址" prop="detail">
					<u-input v-model="form.detail" />
				</u-form-item>
				<u-form-item label="默认地址" prop="is_default">
					<u-switch v-model="form.is_default" :size="40" :active-value="1" :inactive-value="0"
						active-color="#FF504B"></u-switch>
				</u-form-item>
			</u-form>
		</view>
		<u-button type="error" @click="handelSave" shape="circle">立即保存</u-button>
		<gljy-data-picker ref="picker" :idkey="'id'" :isSuper="false" namekey="label" childrenkey="children"
			title="选择所在地区" :initList="initCityList" @load="loadNode" @itemOnclick="itemOnclick" :isLoad="true">
		</gljy-data-picker>
	</view>
</template>

<script>
	import gljyDataPicker from '@/components/gljy-data-picker'
	export default {
		components: {
			'gljy-data-picker': gljyDataPicker,
		},
		props: {

		},
		data() {
			return {
				form: {
					id: '',
					province_id: '',
					city_id: '',
					area_id: '',
					street_id: '',
					detail: '',
					is_default: 0,
					mobile: '',
					real_name: '',
					lng: '',
					lat: '',
					address_id: [],
				},
				rules: {
					real_name: [{
						required: true,
						message: '请输入姓名',
						trigger: ['change', 'blur'],
					}],
					mobile: [{
						required: true,
						message: '请输入联系电话',
						trigger: ['change', 'blur'],
					}],
					address_id: [{
						asyncValidator: (rule, value, callback) => {
							if (!Array.isArray(value)) {
								callback(new Error('所在地区数据类型错误'))
								return
							}
							if (!value.length) {
								callback(new Error('所在地区不能为空'))
								return
							}
							callback()
						},
					}]
				},
				initCityList: [],
				areaNames: '',
			};
		},
		computed: {

		},
		watch: {

		},
		onReady() {
			this.$refs.uForm.setRules(this.rules)
		},
		onLoad(e) {
			const {
				id
			} = e
			let title = ''
			if (id) {
				title = '编辑收货地址'
				this.getAddressDetail(id)
			} else {
				title = '新增收货地址'
			}
			uni.setNavigationBarTitle({
				title
			})
			this.$u.api.getCity({
				pid: 0
			}).then(res => {
				this.initCityList = res
			})
		},
		methods: {
			async getAddressDetail(id) {
				const res = await this.$u.api.readMemberAddress({
					id
				})
				this.form = Object.assign({}, res)
				let areaNames = [res.province, res.city, res.area, res.street].filter((item) => {
					if (item)
						return item
				})
				this.areaNames = areaNames.join(',')
			},
			handelExpressItemClick(item) {
				this.activeItem = item
			},
			handelSave() {
				this.$refs.uForm.validate(async (valid) => {
					if (valid) {
						const res = await this.$u.api.saveMemberAddress(this.form)
						this.$util.msg('保存成功')
						setTimeout(() => {
							this.$util.back()
						}, 500)
					} else {
						console.log('验证失败')
					}
				})
			},
			handelAddressClick() {
				this.$refs.picker._show()
			},
			async loadNode(item, resolve) {
				//获取到当前点击的id值
				let pid = item.id;
				//根据rgid查询后台数据,得到下级数据,没有就返回 [] (建议一开始传入数据的时候,就加一个标记是否是末级的字段)
				let node = await this.$u.api.getCity({
					pid
				})
				resolve(node); //调用回调
			},
			itemOnclick(res) {
				let ids = res.map(item => item.id)
				let names = res.map(item => item.label)
				this.form.address_id = [...ids]
				this.areaNames = names.join(',')
				this.form.province_id = ids.shift()
				this.form.city_id = ids.shift()
				this.form.area_id = ids.shift()
				this.form.street_id = ids.shift()
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.page-container {
		padding: 20rpx;
	}

	.form-box {
		background-color: #fff;
		padding: 0 20rpx;
		margin-bottom: 20rpx;

		::v-deep {
			.u-field {
				padding: 0 !important;
			}
		}
	}
</style>